def destroy_nodes(current_tour: np.ndarray, distance_matrix: np.ndarray,
                  n_destroy: int) -> np.ndarray:
    n = len(current_tour)
    incident_costs = np.array([
        distance_matrix[current_tour[i], current_tour[(i-1) % n]] +
        distance_matrix[current_tour[i], current_tour[(i+1) % n]]
        for i in range(n)
    ])
    detour_costs = np.array([
        distance_matrix[current_tour[(i-1) % n], current_tour[(i+1) % n]]
        for i in range(n)
    ])
    regret = incident_costs * np.maximum(incident_costs - detour_costs, 0)
    if regret.std() > 1e-10:
        temp = regret.std()
    else:
        temp = 1.0
    shifted = regret - regret.min()
    exp_scores = np.exp(shifted / (temp + 1e-10))
    probs = exp_scores / exp_scores.sum()
    chosen_indices = np.random.choice(np.arange(n), size=n_destroy, replace=False, p=probs)
    return current_tour[chosen_indices]

def destroy_nodes(current_tour: np.ndarray, distance_matrix: np.ndarray,
                  n_destroy: int) -> np.ndarray:
    n = len(current_tour)
    if n <= n_destroy:
        return current_tour.copy()

    # Precompute for each node the distance to its two neighbours (cyclic)
    neighbor_dist = np.array([
        distance_matrix[current_tour[i], current_tour[(i+1) % n]] +
        distance_matrix[current_tour[i], current_tour[(i-1) % n]]
        for i in range(n)
    ])

    # For each node, find the maximum distance to any other node in the tour
    max_dist_to_any = np.array([
        np.max(distance_matrix[current_tour[i], current_tour])
        for i in range(n)
    ])

    # Score: neighbor_dist weighted by max_dist_to_any (penalize isolated nodes with high incident cost)
    scores = neighbor_dist * max_dist_to_any

    # Use a sliding window of size n_destroy, find window with highest average score
    best_start = 0
    best_avg = -np.inf
    for start in range(n):
        window_indices = [(start + i) % n for i in range(n_destroy)]
        avg_score = np.mean(scores[window_indices])
        if avg_score > best_avg:
            best_avg = avg_score
            best_start = start

    # Force removal of endpoints of the window for diversity
    endpoints = [best_start, (best_start + n_destroy - 1) % n]
    nodes_to_remove = set()
    nodes_to_remove.add(current_tour[best_start])
    nodes_to_remove.add(current_tour[(best_start + n_destroy - 1) % n])

    # Fill remaining by taking the rest of the window (excluding endpoints already chosen)
    for i in range(n_destroy):
        idx = (best_start + i) % n
        if len(nodes_to_remove) < n_destroy:
            nodes_to_remove.add(current_tour[idx])

    # If still not enough (shouldn't happen), pad randomly
    remaining = [node for node in current_tour if node not in nodes_to_remove]
    while len(nodes_to_remove) < n_destroy and remaining:
        nodes_to_remove.add(np.random.choice(remaining))
        remaining = [node for node in remaining if node not in nodes_to_remove]

    return np.array(list(nodes_to_remove)[:n_destroy])

def destroy_nodes(current_tour: np.ndarray, distance_matrix: np.ndarray,
                  n_destroy: int) -> np.ndarray:
    n = len(current_tour)

    # Compute the sum of incident edge distances for each node
    incident_sums = np.array([
        distance_matrix[current_tour[k], current_tour[(k-1) % n]] +
        distance_matrix[current_tour[k], current_tour[(k+1) % n]]
        for k in range(n)
    ])

    # Add random noise scaled by the standard deviation of incident sums
    noise_scale = np.std(incident_sums) * 0.5
    noise = np.random.normal(0, noise_scale, size=n)
    weighted_scores = incident_sums + noise

    # Select nodes with highest weighted scores, then ensure spatial diversity
    candidates = np.argsort(weighted_scores)[::-1]
    selected = []
    for idx in candidates:
        node = current_tour[idx]
        if len(selected) == 0 or all(
            distance_matrix[node, s] > np.mean(distance_matrix) * 0.3
            for s in selected
        ):
            selected.append(node)
        if len(selected) == n_destroy:
            break

    return np.array(selected)
